+  "use cache";
+
+  cacheLife("minutes");
+  cacheTag("products");
+
+  return readProductsFromSource();
+}
+
+export function getCatalogVersion() {
+  return catalogVersion;
+}
+
+export function isCatalogSyncRunning() {
+  return inFlightSync !== null;
+}
+
+export async function syncLatestCatalog() {
+  if (inFlightSync) {
+    return inFlightSync;
+  }
+
+  inFlightSync = (async () => {
+    await wait(SYNC_DELAY_MS);
+
+    inventorySeed += 1;
+    catalogVersion += 1;
+
+    products = products.map((product, index) => {
+      const priceDelta = (catalogVersion + index) % 2 === 0 ? 10 : -5;
+      const inventory = Math.max(0, product.inventory + ((inventorySeed + index) % 5) - 2);
+      const availability =
+        inventory === 0 ? "Backorder" : inventory < 10 ? "Low stock" : "In stock";
+
+      return {
+        ...product,
+        price: Math.max(25, product.price + priceDelta),
+        inventory,
+        availability,
+      };
+    });
+
+    revalidateTag("products", "max");
+  })();
+
+  try {
+    await inFlightSync;
+  } finally {
+    inFlightSync = null;
+  }
+}
